import { jsx } from 'react/jsx-runtime';
import { AnimatedProgress } from './AnimatedProgress/AnimatedProgress.js';
import { CircleProgress } from './CircleProgress/CircleProgress.js';
import { LinearProgress } from './LinearProgress/LinearProgress.js';

const Progress = ({ value = 0, shape = 'linear', cycled = false, strokeWidth = 4, size = 44, type = 'container', ...props }) => {
    if (shape === 'linear') {
        return jsx(LinearProgress, { value: value, type: type, cycled: cycled, strokeWidth: strokeWidth, ...props });
    }
    if (shape === 'animated') {
        return jsx(AnimatedProgress, { ...props });
    }
    // В случае передачи 0 в круговой прогресс.
    if (!size) {
        return;
    }
    return jsx(CircleProgress, { value: value, cycled: cycled, strokeWidth: strokeWidth, size: size, ...props });
};

export { Progress };
